#define UNIONIZED 0
#define NUCLIDE 1
#define HASH 2

#define STARTING_SEED 1070UL

typedef struct{
	double energy;
	double total_xs;
	double elastic_xs;
	double absorbtion_xs;
	double fission_xs;
	double nu_fission_xs;
} NuclideGridPoint;

typedef struct{
	int nthreads;
	long n_isotopes;
	long n_gridpoints;
	int lookups;
	int HM;
	int grid_type;
	int hash_bins;
	int particles;
	int simulation_method;
	int binary_mode;
	int kernel_id;
	int platform_id;
	int device_id;
} Inputs;

static inline long grid_search(long n, double quarry, __global const double * A)
{
	long lowerLimit = 0;
	long upperLimit = n - 1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( 1 < length )
	{
		examinationPoint = lowerLimit + (length / 2);
		if( quarry < A[examinationPoint] )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}
	return lowerLimit;
}

static inline long grid_search_nuclide(long n, double quarry, __global const NuclideGridPoint * A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( 1 < length )
	{
		examinationPoint = lowerLimit + (length / 2);
		if( quarry < A[examinationPoint].energy )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}
	return lowerLimit;
}

static inline double LCG_random_double(ulong * seed)
{
	const ulong m = 9223372036854775808UL;
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	*seed = (a * (*seed) + c) % m;
	return (double)(*seed) / (double)m;
}

static inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong m = 9223372036854775808UL;
	ulong a = 2806196910506780709UL;
	ulong c = 1UL;

	n = n % m;

	ulong a_new = 1UL;
	ulong c_new = 0UL;

	while( 0UL < n )
	{
		if( n & 1UL )
		{
			a_new = a_new * a;
			c_new = c_new * a + c;
		}
		c = c * (a + 1UL);
		a = a * a;
		n = n >> 1;
	}

	return (a_new * seed + c_new) % m;
}

static inline int pick_mat(ulong * seed)
{
	double dist[12];
	dist[0]  = 0.140;
	dist[1]  = 0.052;
	dist[2]  = 0.275;
	dist[3]  = 0.134;
	dist[4]  = 0.154;
	dist[5]  = 0.064;
	dist[6]  = 0.066;
	dist[7]  = 0.055;
	dist[8]  = 0.008;
	dist[9]  = 0.015;
	dist[10] = 0.025;
	dist[11] = 0.013;

	double roll = LCG_random_double(seed);

	for( int i = 0; i < 12; i++ )
	{
		double running = 0.0;
		for( int j = i; j > 0; j-- )
			running = running + dist[j];
		if( running > roll )
			return i;
	}

	return 0;
}

static inline void calculate_micro_xs(
	double p_energy, int nuc, long n_isotopes, long n_gridpoints,
	__global const double * egrid, __global const int * index_data,
	__global const NuclideGridPoint * nuclide_grids, long idx,
	double * xs_vector, int grid_type, int hash_bins)
{
	double f;
	__global const NuclideGridPoint * low;
	__global const NuclideGridPoint * high;

	if( grid_type == NUCLIDE )
	{
		idx = grid_search_nuclide(n_gridpoints, p_energy, &nuclide_grids[(long)nuc * n_gridpoints], 0, n_gridpoints - 1);

		if( n_gridpoints - 1 == idx )
			low = &nuclide_grids[(long)nuc * n_gridpoints + idx - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + idx];
	}
	else if( grid_type == UNIONIZED )
	{
		long loc = idx * n_isotopes + nuc;
		int base = index_data[loc];
		if( n_gridpoints - 1 == base )
			low = &nuclide_grids[(long)nuc * n_gridpoints + base - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + base];
	}
	else
	{
		int u_low = index_data[idx * n_isotopes + nuc];
		int u_high;
		if( hash_bins - 1 == idx )
			u_high = (int)n_gridpoints - 1;
		else
			u_high = index_data[(idx + 1) * n_isotopes + nuc] + 1;

		double e_low  = nuclide_grids[(long)nuc * n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[(long)nuc * n_gridpoints + u_high].energy;
		int lower;
		if( e_low >= p_energy )
			lower = 0;
		else if( e_high <= p_energy )
			lower = (int)n_gridpoints - 1;
		else
			lower = (int)grid_search_nuclide(n_gridpoints, p_energy, &nuclide_grids[(long)nuc * n_gridpoints], u_low, u_high);

		if( n_gridpoints - 1 == lower )
			low = &nuclide_grids[(long)nuc * n_gridpoints + lower - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + lower];
	}

	high = low + 1;
	f = (high->energy - p_energy) / (high->energy - low->energy);

	xs_vector[0] = high->total_xs      - f * (high->total_xs      - low->total_xs);
	xs_vector[1] = high->elastic_xs    - f * (high->elastic_xs    - low->elastic_xs);
	xs_vector[2] = high->absorbtion_xs - f * (high->absorbtion_xs - low->absorbtion_xs);
	xs_vector[3] = high->fission_xs    - f * (high->fission_xs    - low->fission_xs);
	xs_vector[4] = high->nu_fission_xs - f * (high->nu_fission_xs - low->nu_fission_xs);
}

static inline void calculate_macro_xs(
	double p_energy, int mat, long n_isotopes, long n_gridpoints,
	__global const int * num_nucs, __global const double * concs,
	__global const double * egrid, __global const int * index_data,
	__global const NuclideGridPoint * nuclide_grids, __global const int * mats,
	double * macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs)
{
	int p_nuc;
	long idx = -1;
	double conc;

	for( int k = 0; k < 5; k++ )
		macro_xs_vector[k] = 0.0;

	if( grid_type == UNIONIZED )
		idx = grid_search(n_isotopes * n_gridpoints, p_energy, egrid);
	else if( grid_type == HASH )
	{
		double du = 1.0 / (double)hash_bins;
		idx = (long)(p_energy / du);
	}

	for( int j = 0; j < num_nucs[mat]; j++ )
	{
		double xs_vector[5];
		p_nuc = mats[mat * max_num_nucs + j];
		conc = concs[mat * max_num_nucs + j];

		calculate_micro_xs(
			p_energy, p_nuc, n_isotopes, n_gridpoints,
			egrid, index_data, nuclide_grids, idx, xs_vector, grid_type, hash_bins);

		for( int k = 0; k < 5; k++ )
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}

__kernel void macro_xs_lookup_kernel(
	Inputs in,
	int max_num_nucs,
	__global const int * num_nucs,
	__global const double * concs,
	__global const double * unionized_energy_array,
	__global const int * index_grid,
	__global const NuclideGridPoint * nuclide_grid,
	__global const int * mats,
	__global int * verification)
{
	const int i = (int)get_global_id(0);
	if( in.lookups <= i )
		return;

	ulong seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, (ulong)(2 * i));

	double p_energy = LCG_random_double(&seed);
	int mat = pick_mat(&seed);

	double macro_xs_vector[5];
	calculate_macro_xs(
		p_energy, mat, in.n_isotopes, in.n_gridpoints,
		num_nucs, concs, unionized_energy_array, index_grid,
		nuclide_grid, mats, macro_xs_vector, in.grid_type, in.hash_bins, max_num_nucs);

	double max = -1.0;
	int max_idx = 0;
	for( int j = 0; j < 5; j++ )
	{
		if( max < macro_xs_vector[j] )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	verification[i] = max_idx + 1;
}
